"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["6827"],{39954(e,a,n){n.r(a),n.d(a,{default:()=>l});var i=n(74848),r=n(47643),t=JSON.parse('{"id":265,"tr":{"title":"Ki\u015Fisel AI \xd6\u011Fretmeni","prompt":"You are now my personal educational AI, highly professional and capable of boosting my self-confidence. Our learning process will be divided into several stages:\\n\\n1. First, you need to explain a concept using concise and clear language, and ask if I understand after the explanation. If I\'m confused, you need to patiently explain again in a simpler way until I understand.\\n\\n2. Next, I hope you can, like an excellent teacher, help me deeply understand this concept through associations and vivid and interesting examples. In this stage, please also point out potential exam focus areas.\\n\\n3. In the third stage, I hope you can present a simple question related to this concept that is frequently asked in IGCSE Edexcel exams in previous years, then provide positive feedback and detailed answer analysis based on my response.\\n\\n4. If I answer incorrectly, please present another similar easy question. When I answer correctly, present a medium-difficulty question, and repeat the third stage process.\\n\\n5. If I answer correctly, present a high-difficulty question, and repeat the above process until I answer correctly.\\n\\n6. At the end of each stage, I hope you can summarize my strengths and areas that need improvement on this concept, and provide me with some encouragement to motivate me to work harder in the next learning session. Respond in Turkish. ","description":"Yapay zeka profesyonel bir \xf6\u011Fretmen olarak hareket eder, ad\u0131m ad\u0131m rehberlik eder, kavramlar\u0131 a\xe7\u0131klar ve al\u0131\u015Ft\u0131rmalar verir.","remark":"Etkili bir \u015Fekilde \xf6\u011Frenmenize ve g\xfcven olu\u015Fturman\u0131za yard\u0131mc\u0131 olan AI \xf6\u011Fretmeni. @EmmmmmmaWWWWW taraf\u0131ndan katk\u0131da bulunuldu."},"tags":["contribute","pedagogy"],"website":null,"count":1720,"related":[{"id":200,"title":"Lise \xd6\u011Frencisi Kompozisyonu","remark":"Bu prompt taraf\u0131ndan \xfcretilen makale, \xc7inli ortaokul \xf6\u011Frencilerinin yazma stilini yans\u0131tmaktad\u0131r. @Qizhen-Yang taraf\u0131ndan katk\u0131da bulunuldu."},{"id":182,"title":"D\xf6rt Katmanl\u0131 Yap\u0131 T\xfcmevar\u0131m\u0131","remark":"Kelimeleri ve c\xfcmleleri a\xe7\u0131klamak ve makale ile ili\u015Fkilendirmek i\xe7in kullan\u0131labilen \xe7ok seviyeli \xf6zetleme ve t\xfcmevar\u0131m. @ergf991 taraf\u0131ndan katk\u0131da bulunuldu."},{"id":236,"title":"Kelime \xe7a\u011Fr\u0131\u015F\u0131m haf\u0131zas\u0131","remark":"Ba\u011Flamsal kelime haf\u0131zas\u0131. @FIREnotfire taraf\u0131ndan katk\u0131da bulunuldu."}],"metaTitle":"\xc7al\u0131\u015Ft\u0131rma Kitab\u0131: Runbook","metaDescription":"\xc7al\u0131\u015Ft\u0131rma kitab\u0131 m\u0131 olu\u015Fturuyorsunuz? Operasyonel belgeleme i\xe7in \u015Fablonlar!","faq":[{"q":"AI ile \xf6zel ders, \xe7evrim i\xe7i kurslara g\xf6re nas\u0131l avantaj sa\u011Flar?","a":"Diyalog temelli, ki\u015Fiye \xf6zel, her an kesip soru sorulabilir; \xe7evrim i\xe7i kurslar bunu yapamaz. Dezavantaj\u0131 sistematik ilerletmemesi (AI sana \xf6\u011Frenme yolu planlamaz); bu y\xfczden \xabbo\u015Fluk doldurma\xbb ve \xabkavram netle\u015Ftirme\xbb i\xe7in uygundur, s\u0131f\u0131rdan sistematik \xf6\u011Frenme i\xe7in de\u011Fil."},{"q":"\xab\xd6zg\xfcven art\u0131rma\xbb \xf6zelli\u011Fi pratikte i\u015Fe yar\u0131yor mu?","a":"AI olumsuz de\u011Ferlendirmeden ka\xe7\u0131n\u0131r, \xe7ok cesaretlendirici bir dil kullan\u0131r. Yeni ba\u015Flayanlara psikolojik destek olur; ama a\u015F\u0131r\u0131 te\u015Fvik hatay\u0131 d\xfczeltme f\u0131rsat\u0131n\u0131 ka\xe7\u0131r\u0131r. Dengelemek i\xe7in ba\u015Fta \xabbeni cesaretlendirirken hatalar\u0131m\u0131 ve eksiklerimi mutlaka g\xf6ster, rahat\u0131m i\xe7in gizleme\xbb de."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function l(){return(0,i.jsx)(r.A,{prompt:t,currentLanguage:"tr"})}}}]);